const matches = $input.all().map(i => i.json);
const request = $('Website: New Automation Request').item.json.body;
const embedding = $('Generate Embedding').item.json.data[0].embedding;

const hasMatch = matches.length > 0;

return {
  json: {
    ...request,
    embedding: embedding,
    has_match: hasMatch,
    best_match: hasMatch ? matches[0] : null
  }
};

// Clone matched template's workflow JSON, personalize with client name
const data = $json;
const template = data.best_match.workflow_json;

const personalized = JSON.parse(JSON.stringify(template));
personalized.name = `${data.client_name} - ${data.best_match.template_name}`;

return { json: { ...data, personalized_workflow: personalized } };

let generatedJson;
let isValid = true;
let errorMsg = '';

try {
  // Hamara agent_wrapper_server.py { "output": "..." } shape return karta hai
  // (agar seedha OpenAI API use kar rahe ho to $json.choices[0].message.content use karo)
  const raw = $json.output;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  generatedJson = JSON.parse(cleaned);
  if (!generatedJson.nodes || !generatedJson.connections) {
    isValid = false;
    errorMsg = 'Missing nodes or connections';
  }
} catch (e) {
  isValid = false;
  errorMsg = e.message;
  generatedJson = null;
}

return {
  json: {
    ...($('Evaluate Match').item.json),
    generated_workflow: generatedJson,
    is_valid_json: isValid,
    validation_error: errorMsg
  }
};

